  ?series wdt:P31 wd:Q5232723;
          rdfs:label "Kakegurui"@en;
          wdt:P1708 ?mainChar.
  ?mainChar rdfs:label ?mainCharLabel.
  FILTER(LANG(?mainCharLabel) = 'en')
}

